from datetime import datetime
class ReleaseManager:
    def __init__(self,initial='0.0.0'):
        p=initial.split('.')
        self.major=int(p[0]);self.minor=int(p[1]);self.patch=int(p[2])
        self.releases=[]
    @property
    def version(self):return f'{self.major}.{self.minor}.{self.patch}'
    def bump_major(self):
        self.major+=1;self.minor=0;self.patch=0
        print(f'v{self.version}(MAJOR)')
    def bump_minor(self):
        self.minor+=1;self.patch=0
        print(f'v{self.version}(MINOR)')
    def bump_patch(self):
        self.patch+=1
        print(f'v{self.version}(PATCH)')
    def create_release(self,notes):
        r={'version':self.version,'date':datetime.now().strftime('%Y-%m-%d'),'notes':notes}
        self.releases.append(r)
        print(f'Tagged v{self.version}')
    def get_changelog(self):
        print('\n=== CHANGELOG ===')
        for r in reversed(self.releases):
            print(f'\n## v{r["version"]}({r["date"]})')
            for n in r['notes']:print(f'  -{n}')
rm=ReleaseManager('0.0.0')
